#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct Node {
    int starting;
    int no_of_edges;
} Node;

kernel void BFS_1(Node* x_0, int* g_graph_edges, char* g_graph_mask, char* elem_1, char* v_3, int* g_cost, int tmp_2) 
{
    int tid = get_global_id(0);
